sql:
SELECT signal_name, signal_last_updated
FROM signals
ORDER BY signal_last_updated DESC;

SELECT MAX(version_date) AS latest_version_date
FROM signal_versions
WHERE signal_id = 1;

external_knowledge:
- 'rhythmic heartbeat' refers to the average signal frequency;
- 'start from a blank slate' refers to an initial status of 'Zeros';
- 'have been awakened' refers to active signals (signal_is_active = 1);
- 'beat at an average rate of more than 10,000 times per second' refers to an average frequency greater than 10000 Hz.
